     1→//! Harness CLI - Database utility for AI agents and humans.
     2→//!
     3→//! This CLI provides programmatic access to the Harness storage layer,
     4→//! enabling AI agents to manage tasks, progress, and sessions.
     5→//!
     6→//! ## Usage
     7→//!
     8→//! ```bash
     9→//! harness init                              # Create .harness/harness.db
    10→//! harness db status                         # Show DB info
    11→//! harness task add "Title" [-d "desc"]      # Add a task
    12→//! harness task list [--status=TODO]         # List tasks
    13→//! harness session start                     # Start work session
    14→//! ```
    15→
    16→use clap::{Parser, Subcommand, ValueEnum};
    17→use hq_lib::db;
    18→use std::path::PathBuf;
    19→use std::process::ExitCode;
    20→
    21→// =============================================================================
    22→// CLI STRUCTURE
    23→// =============================================================================
    24→
    25→#[derive(Parser)]
    26→#[command(name = "harness")]
    27→#[command(author, version, about = "Harness CLI - Database utility for AI agents")]
    28→#[command(propagate_version = true)]
    29→struct Cli {
    30→    /// Output format
    31→    #[arg(long, value_enum, global = true, default_value = "text")]
    32→    format: OutputFormat,
    33→
    34→    /// Project directory (defaults to current directory)
    35→    #[arg(short = 'C', long, global = true)]
    36→    dir: Option<PathBuf>,
    37→
    38→    #[command(subcommand)]
    39→    command: Commands,
    40→}
    41→
    42→#[derive(Copy, Clone, PartialEq, Eq, ValueEnum)]
    43→enum OutputFormat {
    44→    /// Human-readable text
    45→    Text,
    46→    /// JSON for programmatic use
    47→    Json,
    48→    /// IDs only (one per line)
    49→    Quiet,
    50→}
    51→
    52→#[derive(Subcommand)]
    53→enum Commands {
    54→    /// Initialize a new Harness project
    55→    Init,
    56→
    57→    /// Database operations
    58→    Db {
    59→        #[command(subcommand)]
    60→        command: DbCommands,
    61→    },
    62→
    63→    /// Task management
    64→    Task {
    65→        #[command(subcommand)]
    66→        command: TaskCommands,
    67→    },
    68→
    69→    /// Task step management
    70→    Step {
    71→        #[command(subcommand)]
    72→        command: StepCommands,
    73→    },
    74→
    75→    /// Work session management
    76→    Session {
    77→        #[command(subcommand)]
    78→        command: SessionCommands,
    79→    },
    80→
    81→    /// Progress log management
    82→    Progress {
    83→        #[command(subcommand)]
    84→        command: ProgressCommands,
    85→    },
    86→
    87→    /// Show project status summary
    88→    Status,
    89→}
    90→
    91→// -----------------------------------------------------------------------------
    92→// DB Subcommands
    93→// -----------------------------------------------------------------------------
    94→
    95→#[derive(Subcommand)]
    96→enum DbCommands {
    97→    /// Show database status and statistics
    98→    Status,
    99→}
   100→
   101→// -----------------------------------------------------------------------------
   102→// Task Subcommands
   103→// -----------------------------------------------------------------------------
   104→
   105→#[derive(Subcommand)]
   106→enum TaskCommands {
   107→    /// Add a new task
   108→    Add {
   109→        /// Task title
   110→        title: String,
   111→
   112→        /// Task description
   113→        #[arg(short, long)]
   114→        description: Option<String>,
   115→
   116→        /// Task category
   117→        #[arg(short, long)]
   118→        category: Option<String>,
   119→
   120→        /// Initial status
   121→        #[arg(short, long, value_enum, default_value = "backlog")]
   122→        status: TaskStatusArg,
   123→    },
   124→
   125→    /// List tasks
   126→    List {
   127→        /// Filter by status
   128→        #[arg(short, long, value_enum)]
   129→        status: Option<TaskStatusArg>,
   130→
   131→        /// Maximum number of results
   132→        #[arg(short, long, default_value = "20")]
   133→        limit: usize,
   134→
   135→        /// Pagination cursor
   136→        #[arg(long)]
   137→        cursor: Option<String>,
   138→    },
   139→
   140→    /// Search tasks using full-text search
   141→    Search {
   142→        /// Search query
   143→        query: String,
   144→
   145→        /// Maximum number of results
   146→        #[arg(short, long, default_value = "20")]
   147→        limit: usize,
   148→    },
   149→
   150→    /// Get a task by ID
   151→    Get {
   152→        /// Task ID (ULID)
   153→        id: String,
   154→    },
   155→
   156→    /// Update a task
   157→    Update {
   158→        /// Task ID (ULID)
   159→        id: String,
   160→
   161→        /// New title
   162→        #[arg(short, long)]
   163→        title: Option<String>,
   164→
   165→        /// New description
   166→        #[arg(short, long)]
   167→        description: Option<String>,
   168→
   169→        /// New category
   170→        #[arg(short, long)]
   171→        category: Option<String>,
   172→
   173→        /// New status
   174→        #[arg(long, value_enum)]
   175→        status: Option<TaskStatusArg>,
   176→
   177→        /// Mark as passed (true/false)
   178→        #[arg(long)]
   179→        passed: Option<bool>,
   180→    },
   181→
   182→    /// Delete a task
   183→    Delete {
   184→        /// Task ID (ULID)
   185→        id: String,
   186→    },
   187→
   188→    /// Reorder a task
   189→    Reorder {
   190→        /// Task ID to move
   191→        id: String,
   192→
   193→        /// Place after this task ID
   194→        #[arg(long)]
   195→        after: String,
   196→    },
   197→}
   198→
   199→#[derive(Copy, Clone, PartialEq, Eq, ValueEnum)]
   200→enum TaskStatusArg {
   201→    Backlog,
   202→    Todo,
   203→    Doing,
   204→    Review,
   205→    Qa,
   206→    Done,
   207→}
   208→
   209→impl From<TaskStatusArg> for db::TaskStatus {
   210→    fn from(arg: TaskStatusArg) -> Self {
   211→        match arg {
   212→            TaskStatusArg::Backlog => db::TaskStatus::Backlog,
   213→            TaskStatusArg::Todo => db::TaskStatus::Todo,
   214→            TaskStatusArg::Doing => db::TaskStatus::Doing,
   215→            TaskStatusArg::Review => db::TaskStatus::Review,
   216→            TaskStatusArg::Qa => db::TaskStatus::Qa,
   217→            TaskStatusArg::Done => db::TaskStatus::Done,
   218→        }
   219→    }
   220→}
   221→
   222→// -----------------------------------------------------------------------------
   223→// Step Subcommands
   224→// -----------------------------------------------------------------------------
   225→
   226→#[derive(Subcommand)]
   227→enum StepCommands {
   228→    /// Add a step to a task
   229→    Add {
   230→        /// Parent task ID
   231→        task_id: String,
   232→
   233→        /// Step description
   234→        description: String,
   235→    },
   236→
   237→    /// List steps for a task
   238→    List {
   239→        /// Parent task ID
   240→        task_id: String,
   241→    },
   242→
   243→    /// Mark a step as complete
   244→    Complete {
   245→        /// Step ID
   246→        id: String,
   247→    },
   248→
   249→    /// Mark a step as incomplete
   250→    Uncomplete {
   251→        /// Step ID
   252→        id: String,
   253→    },
   254→
   255→    /// Toggle step completion
   256→    Toggle {
   257→        /// Step ID
   258→        id: String,
   259→    },
   260→
   261→    /// Delete a step
   262→    Delete {
   263→        /// Step ID
   264→        id: String,
   265→    },
   266→}
   267→
   268→// -----------------------------------------------------------------------------
   269→// Session Subcommands
   270→// -----------------------------------------------------------------------------
   271→
   272→#[derive(Subcommand)]
   273→enum SessionCommands {
   274→    /// Start a new work session
   275→    Start {
   276→        /// Session summary
   277→        #[arg(short, long)]
   278→        summary: Option<String>,
   279→    },
   280→
   281→    /// End the current session
   282→    End {
   283→        /// Final summary
   284→        #[arg(short, long)]
   285→        summary: Option<String>,
   286→    },
   287→
   288→    /// Show current active session
   289→    Current,
   290→
   291→    /// List sessions
   292→    List {
   293→        /// Maximum number of results
   294→        #[arg(short, long, default_value = "20")]
   295→        limit: usize,
   296→
   297→        /// Pagination cursor
   298→        #[arg(long)]
   299→        cursor: Option<String>,
   300→    },
   301→
   302→    /// Get a session by ID
   303→    Get {
   304→        /// Session ID (ULID)
   305→        id: String,
   306→    },
   307→}
   308→
   309→// -----------------------------------------------------------------------------
   310→// Progress Subcommands
   311→// -----------------------------------------------------------------------------
   312→
   313→#[derive(Subcommand)]
   314→enum ProgressCommands {
   315→    /// Add a progress entry
   316→    Add {
   317→        /// Progress content
   318→        content: String,
   319→
   320→        /// Session ID (uses current session if not specified)
   321→        #[arg(short, long)]
   322→        session: Option<String>,
   323→    },
   324→
   325→    /// List progress entries
   326→    List {
   327→        /// Filter by session ID
   328→        #[arg(short, long)]
   329→        session: Option<String>,
   330→
   331→        /// Maximum number of results
   332→        #[arg(short, long, default_value = "20")]
   333→        limit: usize,
   334→
   335→        /// Pagination cursor
   336→        #[arg(long)]
   337→        cursor: Option<String>,
   338→    },
   339→
   340→    /// Search progress using full-text search
   341→    Search {
   342→        /// Search query
   343→        query: String,
   344→
   345→        /// Maximum number of results
   346→        #[arg(short, long, default_value = "20")]
   347→        limit: usize,
   348→    },
   349→}
   350→
   351→// =============================================================================
   352→// MAIN
   353→// =============================================================================
   354→
   355→fn main() -> ExitCode {
   356→    let cli = Cli::parse();
   357→
   358→    // Determine project directory
   359→    let project_dir = cli.dir.unwrap_or_else(|| std::env::current_dir().unwrap_or_default());
   360→
   361→    let result = match cli.command {
   362→        Commands::Init => cmd_init(&project_dir, cli.format),
   363→        Commands::Db { command } => match command {
   364→            DbCommands::Status => cmd_db_status(&project_dir, cli.format),
   365→        },
   366→        Commands::Task { command } => cmd_task(&project_dir, command, cli.format),
   367→        Commands::Step { command } => cmd_step(&project_dir, command, cli.format),
   368→        Commands::Session { command } => cmd_session(&project_dir, command, cli.format),
   369→        Commands::Progress { command } => cmd_progress(&project_dir, command, cli.format),
   370→        Commands::Status => cmd_status(&project_dir, cli.format),
   371→    };
   372→
   373→    match result {
   374→        Ok(()) => ExitCode::SUCCESS,
   375→        Err(e) => {
   376→            eprintln!("Error: {}", e);
   377→            match e {
   378→                CliError::NotHarnessProject => ExitCode::from(2),
   379→                CliError::Database(_) => ExitCode::from(3),
   380→                _ => ExitCode::FAILURE,
   381→            }
   382→        }
   383→    }
   384→}
   385→
   386→// =============================================================================
   387→// ERROR HANDLING
   388→// =============================================================================
   389→
   390→#[derive(Debug)]
   391→enum CliError {
   392→    NotHarnessProject,
   393→    Database(db::DbError),
   394→    NotFound(String),
   395→    NoActiveSession,
   396→    Io(std::io::Error),
   397→}
   398→
   399→impl std::fmt::Display for CliError {
   400→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
   401→        match self {
   402→            CliError::NotHarnessProject => write!(f, "Not a Harness project (no .harness/ folder)"),
   403→            CliError::Database(e) => write!(f, "Database error: {}", e),
   404→            CliError::NotFound(what) => write!(f, "Not found: {}", what),
   405→            CliError::NoActiveSession => write!(f, "No active session"),
   406→            CliError::Io(e) => write!(f, "IO error: {}", e),
   407→        }
   408→    }
   409→}
   410→
   411→impl From<db::DbError> for CliError {
   412→    fn from(e: db::DbError) -> Self {
   413→        CliError::Database(e)
   414→    }
   415→}
   416→
   417→impl From<std::io::Error> for CliError {
   418→    fn from(e: std::io::Error) -> Self {
   419→        CliError::Io(e)
   420→    }
   421→}
   422→
   423→type CliResult<T> = Result<T, CliError>;
   424→
   425→// =============================================================================
   426→// COMMAND IMPLEMENTATIONS
   427→// =============================================================================
   428→
   429→fn cmd_init(project_dir: &PathBuf, format: OutputFormat) -> CliResult<()> {
   430→    let harness_dir = project_dir.join(db::HARNESS_FOLDER);
   431→
   432→    // Create .harness/ if it doesn't exist
   433→    if !harness_dir.exists() {
   434→        std::fs::create_dir_all(&harness_dir)?;
   435→    }
   436→
   437→    // Open or create the database
   438→    let conn = db::open_or_create(project_dir)?;
   439→
   440→    let db_path = db::get_db_path(project_dir);
   441→
   442→    match format {
   443→        OutputFormat::Json => {
   444→            println!(
   445→                r#"{{"success":true,"path":"{}","version":"{}"}}"#,
   446→                db_path.display(),
   447→                db::SCHEMA_VERSION
   448→            );
   449→        }
   450→        OutputFormat::Quiet => {
   451→            println!("{}", db_path.display());
   452→        }
   453→        OutputFormat::Text => {
   454→            println!("Initialized Harness database at {}", db_path.display());
   455→            println!("Schema version: {}", db::SCHEMA_VERSION);
   456→
   457→            // Show stats
   458→            let stats = db::DbStats::collect(&conn, Some(&db_path))?;
   459→            println!("\nDatabase stats:");
   460→            println!("  Tasks:    {}", stats.task_count);
   461→            println!("  Steps:    {}", stats.step_count);
   462→            println!("  Sessions: {}", stats.session_count);
   463→            println!("  Progress: {}", stats.progress_count);
   464→        }
   465→    }
   466→
   467→    Ok(())
   468→}
   469→
   470→fn cmd_db_status(project_dir: &PathBuf, format: OutputFormat) -> CliResult<()> {
   471→    if !db::has_harness_folder(project_dir) {
   472→        return Err(CliError::NotHarnessProject);
   473→    }
   474→
   475→    let conn = db::open(project_dir)?;
   476→    let db_path = db::get_db_path(project_dir);
   477→    let stats = db::DbStats::collect(&conn, Some(&db_path))?;
   478→    let version = db::get_schema_version(&conn)?.unwrap_or_else(|| "unknown".to_string());
   479→
   480→    match format {
   481→        OutputFormat::Json => {
   482→            println!(
   483→                r#"{{"path":"{}","version":"{}","size_bytes":{},"tasks":{},"steps":{},"sessions":{},"progress":{}}}"#,
   484→                db_path.display(),
   485→                version,
   486→                stats.file_size_bytes,
   487→                stats.task_count,
   488→                stats.step_count,
   489→                stats.session_count,
   490→                stats.progress_count
   491→            );
   492→        }
   493→        OutputFormat::Quiet => {
   494→            println!("{}", db_path.display());
   495→        }
   496→        OutputFormat::Text => {
   497→            println!("Database: {}", db_path.display());
   498→            println!("Schema version: {}", version);
   499→            println!("Size: {} bytes", stats.file_size_bytes);
   500→            println!();
   501→            println!("Counts:");
   502→            println!("  Tasks:    {}", stats.task_count);
   503→            println!("  Steps:    {}", stats.step_count);
   504→            println!("  Sessions: {}", stats.session_count);
   505→            println!("  Progress: {}", stats.progress_count);
   506→        }
   507→    }
   508→
   509→    Ok(())
   510→}
   511→
   512→fn cmd_task(project_dir: &PathBuf, command: TaskCommands, format: OutputFormat) -> CliResult<()> {
   513→    if !db::has_harness_folder(project_dir) {
   514→        return Err(CliError::NotHarnessProject);
   515→    }
   516→
   517→    let conn = db::open(project_dir)?;
   518→
   519→    match command {
   520→        TaskCommands::Add {
   521→            title,
   522→            description,
   523→            category,
   524→            status,
   525→        } => {
   526→            let mut task = db::ProjectTask::new(&title).with_status(status.into());
   527→
   528→            if let Some(ref desc) = description {
   529→                task = task.with_description(desc);
   530→            }
   531→            if let Some(ref cat) = category {
   532→                task = task.with_category(cat);
   533→            }
   534→
   535→            db::create_task(&conn, &task)?;
   536→
   537→            match format {
   538→                OutputFormat::Json => {
   539→                    println!("{}", serde_json::to_string(&task).unwrap_or_default());
   540→                }
   541→                OutputFormat::Quiet => {
   542→                    println!("{}", task.id);
   543→                }
   544→                OutputFormat::Text => {
   545→                    println!("Created task: {}", task.id);
   546→                    println!("  Title:  {}", task.title);
   547→                    println!("  Status: {}", task.status.as_str());
   548→                }
   549→            }
   550→        }
   551→
   552→        TaskCommands::List { status, limit, cursor } => {
   553→            let result = if let Some(status) = status {
   554→                db::list_tasks_by_status(&conn, status.into(), cursor.as_deref(), Some(limit))?
   555→            } else {
   556→                db::list_tasks(&conn, cursor.as_deref(), Some(limit))?
   557→            };
   558→
   559→            match format {
   560→                OutputFormat::Json => {
   561→                    println!("{}", serde_json::to_string(&result).unwrap_or_default());
   562→                }
   563→                OutputFormat::Quiet => {
   564→                    for task in &result.items {
   565→                        println!("{}", task.id);
   566→                    }
   567→                }
   568→                OutputFormat::Text => {
   569→                    if result.items.is_empty() {
   570→                        println!("No tasks found.");
   571→                    } else {
   572→                        println!("{:<26}  {:<8}  {}", "ID", "STATUS", "TITLE");
   573→                        println!("{}", "-".repeat(70));
   574→                        for task in &result.items {
   575→                            println!(
   576→                                "{:<26}  {:<8}  {}",
   577→                                task.id,
   578→                                task.status.as_str(),
   579→                                truncate(&task.title, 32)
   580→                            );
   581→                        }
   582→                        if result.has_next {
   583→                            println!();
   584→                            println!("More results available. Use --cursor={}", result.next_cursor.as_deref().unwrap_or(""));
   585→                        }
   586→                    }
   587→                }
   588→            }
   589→        }
   590→
   591→        TaskCommands::Search { query, limit } => {
   592→            let tasks = db::search_tasks(&conn, &query, Some(limit))?;
   593→
   594→            match format {
   595→                OutputFormat::Json => {
   596→                    println!("{}", serde_json::to_string(&tasks).unwrap_or_default());
   597→                }
   598→                OutputFormat::Quiet => {
   599→                    for task in &tasks {
   600→                        println!("{}", task.id);
   601→                    }
   602→                }
   603→                OutputFormat::Text => {
   604→                    if tasks.is_empty() {
   605→                        println!("No tasks found matching '{}'.", query);
   606→                    } else {
   607→                        println!("Found {} task(s) matching '{}':", tasks.len(), query);
   608→                        println!();
   609→                        println!("{:<26}  {:<8}  {}", "ID", "STATUS", "TITLE");
   610→                        println!("{}", "-".repeat(70));
   611→                        for task in &tasks {
   612→                            println!(
   613→                                "{:<26}  {:<8}  {}",
   614→                                task.id,
   615→                                task.status.as_str(),
   616→                                truncate(&task.title, 32)
   617→                            );
   618→                        }
   619→                    }
   620→                }
   621→            }
   622→        }
   623→
   624→        TaskCommands::Get { id } => {
   625→            let task = db::get_task(&conn, &id)?
   626→                .ok_or_else(|| CliError::NotFound(format!("Task {}", id)))?;
   627→
   628→            match format {
   629→                OutputFormat::Json => {
   630→                    println!("{}", serde_json::to_string(&task).unwrap_or_default());
   631→                }
   632→                OutputFormat::Quiet => {
   633→                    println!("{}", task.id);
   634→                }
   635→                OutputFormat::Text => {
   636→                    println!("ID:          {}", task.id);
   637→                    println!("Title:       {}", task.title);
   638→                    println!("Status:      {}", task.status.as_str());
   639→                    println!("Category:    {}", task.category.as_deref().unwrap_or("-"));
   640→                    println!("Description: {}", task.description.as_deref().unwrap_or("-"));
   641→                    println!("Passed:      {}", task.is_passed);
   642→                    println!("Order:       {:.2}", task.sort_order);
   643→                    println!("Created:     {}", task.created_at);
   644→                    println!("Updated:     {}", task.updated_at);
   645→
   646→                    // Show steps
   647→                    let steps = db::list_steps(&conn, &id)?;
   648→                    if !steps.is_empty() {
   649→                        println!();
   650→                        println!("Steps ({}):", steps.len());
   651→                        for step in &steps {
   652→                            let check = if step.is_completed { "[x]" } else { "[ ]" };
   653→                            println!("  {} {}", check, step.description);
   654→                        }
   655→                    }
   656→                }
   657→            }
   658→        }
   659→
   660→        TaskCommands::Update {
   661→            id,
   662→            title,
   663→            description,
   664→            category,
   665→            status,
   666→            passed,
   667→        } => {
   668→            let mut update = db::TaskUpdate::default();
   669→            update.title = title;
   670→            update.description = description.map(Some);
   671→            update.category = category.map(Some);
   672→            update.status = status.map(|s| s.into());
   673→
   674→            let updated = db::update_task(&conn, &id, update)?;
   675→
   676→            if let Some(p) = passed {
   677→                db::set_task_passed(&conn, &id, p)?;
   678→            }
   679→
   680→            if !updated && passed.is_none() {
   681→                return Err(CliError::NotFound(format!("Task {}", id)));
   682→            }
   683→
   684→            match format {
   685→                OutputFormat::Json => {
   686→                    if let Some(task) = db::get_task(&conn, &id)? {
   687→                        println!("{}", serde_json::to_string(&task).unwrap_or_default());
   688→                    }
   689→                }
   690→                OutputFormat::Quiet => {
   691→                    println!("{}", id);
   692→                }
   693→                OutputFormat::Text => {
   694→                    println!("Updated task: {}", id);
   695→                }
   696→            }
   697→        }
   698→
   699→        TaskCommands::Delete { id } => {
   700→            // Delete steps first
   701→            db::delete_steps_for_task(&conn, &id)?;
   702→
   703→            let deleted = db::delete_task(&conn, &id)?;
   704→            if !deleted {
   705→                return Err(CliError::NotFound(format!("Task {}", id)));
   706→            }
   707→
   708→            match format {
   709→                OutputFormat::Json => {
   710→                    println!(r#"{{"deleted":true,"id":"{}"}}"#, id);
   711→                }
   712→                OutputFormat::Quiet => {
   713→                    println!("{}", id);
   714→                }
   715→                OutputFormat::Text => {
   716→                    println!("Deleted task: {}", id);
   717→                }
   718→            }
   719→        }
   720→
   721→        TaskCommands::Reorder { id, after } => {
   722→            let new_order = db::get_order_after(&conn, Some(&after))?;
   723→            let mut update = db::TaskUpdate::default();
   724→            update.sort_order = Some(new_order);
   725→
   726→            let updated = db::update_task(&conn, &id, update)?;
   727→            if !updated {
   728→                return Err(CliError::NotFound(format!("Task {}", id)));
   729→            }
   730→
   731→            match format {
   732→                OutputFormat::Json => {
   733→                    println!(r#"{{"id":"{}","sort_order":{}}}"#, id, new_order);
   734→                }
   735→                OutputFormat::Quiet => {
   736→                    println!("{}", id);
   737→                }
   738→                OutputFormat::Text => {
   739→                    println!("Reordered task {} after {}", id, after);
   740→                }
   741→            }
   742→        }
   743→    }
   744→
   745→    Ok(())
   746→}
