fn truncate(s: &str, max_len: usize) -> String {
    if s.len() <= max_len {
        s.to_string()
    } else {
        format!("{}...", &s[..max_len.saturating_sub(3)])
    }
}

//! Project progress CRUD operations.
//!
//! This module provides CRUD operations for project progress entries.
//! Progress entries are log messages within work sessions, using composite IDs.
//!
//! ## Composite ID Format
//!
//! `session#{session_ulid}#{progress_ulid}`
//!
//! This allows efficient prefix queries: `WHERE id GLOB 'session#<session_id>#*'`
//!
//! ## FTS5 Search
//!
//! Progress content is indexed in `project_progress_fts` for full-text search.

use chrono::Utc;
use rusqlite::{params, Connection, OptionalExtension};

use super::types::{PaginatedResult, ProjectProgress};
use super::DbResult;

// =============================================================================
// CREATE
// =============================================================================

/// Create a new progress entry (internal use).
pub fn create_progress(conn: &Connection, progress: &ProjectProgress) -> DbResult<()> {
    conn.execute(
        r#"
        INSERT INTO project_progress (id, content, created_at)
        VALUES (?1, ?2, ?3)
        "#,
        params![
            progress.id,
            progress.content,
            progress.created_at.to_rfc3339(),
        ],
    )?;
    Ok(())
}

/// Add a progress entry to a session.
///
/// Generates the progress ID automatically.
pub fn add_progress(conn: &Connection, session_id: &str, content: &str) -> DbResult<ProjectProgress> {
    let progress = ProjectProgress::new(session_id, content)?;
    create_progress(conn, &progress)?;
    Ok(progress)
}

// =============================================================================
// READ
// =============================================================================

/// Get a progress entry by ID.
pub fn get_progress(conn: &Connection, id: &str) -> DbResult<Option<ProjectProgress>> {
    let result = conn
        .query_row(
            r#"
            SELECT id, content, created_at
            FROM project_progress
            WHERE id = ?1
            "#,
            [id],
            |row| row_to_progress(row),
        )
        .optional()?;
    Ok(result)
}

/// List all progress entries for a session.
///
/// Returns entries ordered by creation time (ULID order).
pub fn list_progress_for_session(conn: &Connection, session_id: &str) -> DbResult<Vec<ProjectProgress>> {
    let pattern = ProjectProgress::glob_pattern(session_id);

    let mut stmt = conn.prepare(
        r#"
        SELECT id, content, created_at
        FROM project_progress
        WHERE id GLOB ?1
        ORDER BY id ASC
        "#,
    )?;

    let rows = stmt.query_map([pattern], |row| row_to_progress(row))?;

    let mut entries = Vec::new();
    for row in rows {
        entries.push(row?);
    }

    Ok(entries)
}

/// List all progress entries with pagination.
///
/// Returns entries ordered by creation time (most recent first).
pub fn list_progress(
    conn: &Connection,
    cursor: Option<&str>,
    limit: Option<usize>,
) -> DbResult<PaginatedResult<ProjectProgress>> {
    let limit = limit.unwrap_or(super::tasks::DEFAULT_PAGE_SIZE);

    let after_id = cursor
        .map(|c| super::tasks::decode_cursor(c))
        .transpose()?;

    let mut entries = Vec::new();

    if let Some(after_id) = after_id {
        // Get the created_at of the cursor entry
        let cursor_created: Option<String> = conn
            .query_row(
                "SELECT created_at FROM project_progress WHERE id = ?1",
                [&after_id],
                |row| row.get(0),
            )
            .optional()?;

        if let Some(created) = cursor_created {
            let mut stmt = conn.prepare(
                r#"
                SELECT id, content, created_at
                FROM project_progress
                WHERE (created_at < ?1) OR (created_at = ?1 AND id < ?2)
                ORDER BY created_at DESC, id DESC
                LIMIT ?3
                "#,
            )?;

            let rows = stmt.query_map(params![created, after_id, (limit + 1) as i64], |row| {
                row_to_progress(row)
            })?;
            for row in rows {
                entries.push(row?);
            }
        }
    } else {
        let mut stmt = conn.prepare(
            r#"
            SELECT id, content, created_at
            FROM project_progress
            ORDER BY created_at DESC, id DESC
            LIMIT ?1
            "#,
        )?;

        let rows = stmt.query_map([(limit + 1) as i64], |row| row_to_progress(row))?;
        for row in rows {
            entries.push(row?);
        }
    }

    let has_next = entries.len() > limit;
    if has_next {
        entries.pop();
    }

    let has_prev = cursor.is_some();

    let next_cursor = if has_next {
        entries.last().map(|p| super::tasks::encode_cursor(&p.id))
    } else {
        None
    };

    let prev_cursor = if has_prev {
        entries.first().map(|p| super::tasks::encode_cursor(&p.id))
    } else {
        None
    };

    Ok(PaginatedResult::new(
        entries,
        has_next,
        has_prev,
        next_cursor,
        prev_cursor,
    ))
}

