//! Task CRUD operations.
//!
//! This module provides Create, Read, Update, Delete operations for project tasks.
//! Features:
//! - Full CRUD operations
//! - Pagination with cursor-based navigation
//! - Full-text search via FTS5
//! - Status filtering
//! - Reordering with fractional sort_order

use chrono::Utc;
use rusqlite::{params, Connection, OptionalExtension};

use super::types::{PaginatedResult, ProjectTask, TaskStatus};
use super::DbResult;

/// Default page size for list operations.
pub const DEFAULT_PAGE_SIZE: usize = 50;

// =============================================================================
// CREATE
// =============================================================================

/// Create a new task.
pub fn create_task(conn: &Connection, task: &ProjectTask) -> DbResult<()> {
    conn.execute(
        r#"
        INSERT INTO project_tasks (id, title, description, status, category, sort_order, is_passed, created_at, updated_at)
        VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8, ?9)
        "#,
        params![
            task.id,
            task.title,
            task.description,
            task.status.as_str(),
            task.category,
            task.sort_order,
            if task.is_passed { "true" } else { "false" },
            task.created_at.to_rfc3339(),
            task.updated_at.to_rfc3339(),
        ],
    )?;
    Ok(())
}

// =============================================================================
// READ
// =============================================================================

/// Get a task by ID.
pub fn get_task(conn: &Connection, id: &str) -> DbResult<Option<ProjectTask>> {
    let result = conn
        .query_row(
            r#"
            SELECT id, title, description, status, category, sort_order, is_passed, created_at, updated_at
            FROM project_tasks
            WHERE id = ?1
            "#,
            [id],
            |row| row_to_task(row),
        )
        .optional()?;
    Ok(result)
}

/// List all tasks with pagination.
///
/// Returns tasks ordered by sort_order, then created_at.
pub fn list_tasks(
    conn: &Connection,
    cursor: Option<&str>,
    limit: Option<usize>,
) -> DbResult<PaginatedResult<ProjectTask>> {
    let limit = limit.unwrap_or(DEFAULT_PAGE_SIZE);

    // Decode cursor if present
    let after_id = cursor.map(|c| decode_cursor(c)).transpose()?;

    let mut tasks = Vec::new();

    if let Some(after_id) = after_id {
        // Get the sort_order of the cursor task
        let cursor_order: Option<f64> = conn
            .query_row(
                "SELECT sort_order FROM project_tasks WHERE id = ?1",
                [&after_id],
                |row| row.get(0),
            )
            .optional()?;

        if let Some(order) = cursor_order {
            // Get tasks after the cursor
            let mut stmt = conn.prepare(
                r#"
                SELECT id, title, description, status, category, sort_order, is_passed, created_at, updated_at
                FROM project_tasks
                WHERE (sort_order > ?1) OR (sort_order = ?1 AND id > ?2)
                ORDER BY sort_order ASC, id ASC
                LIMIT ?3
                "#,
            )?;

            let rows = stmt.query_map(params![order, after_id, (limit + 1) as i64], |row| row_to_task(row))?;
            for row in rows {
                tasks.push(row?);
            }
        }
    } else {
        // No cursor, get from the beginning
        let mut stmt = conn.prepare(
            r#"
            SELECT id, title, description, status, category, sort_order, is_passed, created_at, updated_at
            FROM project_tasks
            ORDER BY sort_order ASC, id ASC
            LIMIT ?1
            "#,
        )?;

        let rows = stmt.query_map([(limit + 1) as i64], |row| row_to_task(row))?;
        for row in rows {
            tasks.push(row?);
        }
    }

    // Check if there are more results
    let has_next = tasks.len() > limit;
    if has_next {
        tasks.pop(); // Remove the extra item
    }

    // Has prev if we used a cursor
    let has_prev = cursor.is_some();

    // Generate cursors
    let next_cursor = if has_next {
        tasks.last().map(|t| encode_cursor(&t.id))
    } else {
        None
    };

    let prev_cursor = if has_prev {
        tasks.first().map(|t| encode_cursor(&t.id))
    } else {
        None
    };

    Ok(PaginatedResult::new(tasks, has_next, has_prev, next_cursor, prev_cursor))
}

