### 4. **Database Search Function Signatures**

**File:** `/Users/anotonio.silva/antonio/HQ/src-tauri/src/db/tasks.rs` (lines 230-257):
```rust
/// Search tasks using full-text search.
pub fn search_tasks(
    conn: &Connection,
    query: &str,
    limit: Option<usize>,
) -> DbResult<Vec<ProjectTask>> {
    let limit = limit.unwrap_or(DEFAULT_PAGE_SIZE);

    let mut stmt = conn.prepare(
        r#"
        SELECT p.id, p.title, p.description, p.status, p.category, p.sort_order, p.is_passed, p.created_at, p.updated_at
        FROM project_tasks p
        JOIN project_tasks_fts fts ON p.rowid = fts.rowid
        WHERE project_tasks_fts MATCH ?1
        ORDER BY rank
        LIMIT ?2
        "#,
    )?;

    let rows = stmt.query_map(params![query, limit as i64], |row| row_to_task(row))?;
    // ... row collection
}
```

